/**
 * Offscreen Three.js thumbnail renderer for yapCAD packages.
 * Generated by qwen3-coder:30b, reviewed and refined by Jarvis.
 */

import * as THREE from 'three';
import { get, set } from 'idb-keyval';

export interface GeometryEntity {
  id: string;
  name?: string;
  vertices: Float32Array;
  normals?: Float32Array;
  indices?: Uint32Array;
  material?: string;
  layer?: string;
}

const THUMBNAIL_CACHE_PREFIX = 'yapcad-thumb-';

/**
 * Render an offscreen thumbnail of geometry entities.
 * Creates a temporary WebGL renderer, renders one frame, returns data URL.
 * All resources are disposed after rendering.
 */
export async function renderThumbnail(
  entities: GeometryEntity[],
  size: number = 256
): Promise<string> {
  if (entities.length === 0) {
    throw new Error('No geometry entities to render');
  }

  // Create offscreen renderer
  const renderer = new THREE.WebGLRenderer({
    antialias: true,
    preserveDrawingBuffer: true,
    alpha: false,
  });
  renderer.setSize(size, size);
  renderer.setPixelRatio(1);

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x1a1a2e);

  // Camera
  const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 10000);

  // 3-point lighting
  const ambient = new THREE.AmbientLight(0x404040, 0.5);
  scene.add(ambient);

  const keyLight = new THREE.DirectionalLight(0xffffff, 1.0);
  keyLight.position.set(10, 20, 20);
  scene.add(keyLight);

  const fillLight = new THREE.DirectionalLight(0x8888ff, 0.4);
  fillLight.position.set(-10, -10, 20);
  scene.add(fillLight);

  const rimLight = new THREE.DirectionalLight(0xffffff, 0.3);
  rimLight.position.set(0, 10, -20);
  scene.add(rimLight);

  // Build meshes
  const meshes: THREE.Mesh[] = [];
  const materials: THREE.Material[] = [];

  for (const entity of entities) {
    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.BufferAttribute(entity.vertices, 3));

    if (entity.normals && entity.normals.length > 0) {
      geometry.setAttribute('normal', new THREE.BufferAttribute(entity.normals, 3));
    } else {
      geometry.computeVertexNormals();
    }

    if (entity.indices && entity.indices.length > 0) {
      geometry.setIndex(new THREE.BufferAttribute(entity.indices, 1));
    }

    const material = new THREE.MeshStandardMaterial({
      color: 0x99bbdd,
      metalness: 0.2,
      roughness: 0.4,
      side: THREE.DoubleSide,
    });

    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);
    meshes.push(mesh);
    materials.push(material);
  }

  // Compute bounding box AFTER adding to scene (ensures world transforms apply)
  const box = new THREE.Box3();
  for (const mesh of meshes) {
    mesh.geometry.computeBoundingBox();
    if (mesh.geometry.boundingBox) {
      box.union(mesh.geometry.boundingBox);
    }
  }

  if (box.isEmpty()) {
    // Fallback: try expandByObject
    for (const mesh of meshes) {
      box.expandByObject(mesh);
    }
  }

  // Fit camera — centered isometric view
  const center = box.getCenter(new THREE.Vector3());
  const bsize = box.getSize(new THREE.Vector3());
  const maxDim = Math.max(bsize.x, bsize.y, bsize.z) || 1;
  const fovRad = camera.fov * (Math.PI / 180);
  const distance = (maxDim / (2 * Math.tan(fovRad / 2))) * 1.8;

  camera.position.set(
    center.x + distance * 0.6,
    center.y + distance * 0.4,
    center.z + distance * 0.7
  );
  camera.lookAt(center);
  camera.updateProjectionMatrix();

  // Render
  renderer.render(scene, camera);
  const dataUrl = renderer.domElement.toDataURL('image/png');

  // Dispose everything
  for (const mesh of meshes) {
    mesh.geometry.dispose();
  }
  for (const mat of materials) {
    mat.dispose();
  }
  renderer.dispose();

  return dataUrl;
}

/**
 * Get a cached thumbnail by package UUID.
 */
export async function getCachedThumbnail(uuid: string): Promise<string | null> {
  try {
    const cached = await get<string>(THUMBNAIL_CACHE_PREFIX + uuid);
    return cached ?? null;
  } catch {
    return null;
  }
}

/**
 * Cache a thumbnail data URL by package UUID.
 */
export async function cacheThumbnail(uuid: string, dataUrl: string): Promise<void> {
  try {
    await set(THUMBNAIL_CACHE_PREFIX + uuid, dataUrl);
  } catch {
    // Cache failure is non-fatal
    console.warn('Failed to cache thumbnail for', uuid);
  }
}
